-- Jalankan SETELAH schema.sql. Aman diulang (upsert on conflict id).
on conflict (id) do update set
  gross_kg=excluded.gross_kg, tare_kg=excluded.tare_kg, netto_kg=excluded.netto_kg,
  date_out=excluded.date_out, time_out=excluded.time_out, status=excluded.status;